function quickSetupMapPanel() {
  const panel = document.createElement("div");
  panel.className = "quick-setup-map";
  panel.dataset.settingsSearch = normalizeSettingsQuery("quick setup map current setup appearance layout terminal browser speed performance profiles jump configure customize");
  panel.innerHTML = `
    <div class="quick-map-heading">
      <span class="quick-map-title">Setup map</span>
      <span class="quick-map-subtitle">Jump to the page that owns each part of the current setup.</span>
    </div>
    <div class="quick-map-grid"></div>
  `;
  const grid = panel.querySelector(".quick-map-grid");
  for (const item of quickSetupMapItems()) {
    const button = document.createElement("button");
    button.className = "quick-map-card";
    button.type = "button";
    button.title = `Open ${item.label} settings.`;
    button.dataset.settingsSearch = normalizeSettingsQuery(`quick setup map ${item.search} ${item.label} ${item.value} ${item.body} ${item.meta}`);
    button.innerHTML = `
      <span class="quick-map-icon" aria-hidden="true"></span>
      <span class="quick-map-copy">
        <span class="quick-map-label-row">
          <span class="quick-map-label"></span>
          <span class="quick-map-value"></span>
        </span>
        <span class="quick-map-body"></span>
        <span class="quick-map-meta"></span>
      </span>
    `;
    button.querySelector(".quick-map-icon").innerHTML = quickActionIconMarkup(item.icon);
    button.querySelector(".quick-map-label").textContent = item.label;
    button.querySelector(".quick-map-value").textContent = item.value || "Open";
    button.querySelector(".quick-map-body").textContent = item.body || "";
    button.querySelector(".quick-map-meta").textContent = item.meta || "";
    button.onclick = () => openSettingsCategory(item.category);
    grid.append(button);
  }
  return panel;
}

const quickSetupPresetRailItems = [
  { id: "simpleFast", label: "Clean + Fast", body: "Simple speed", icon: "speed", search: "clean fast simple minimal ui speed performance lag startup" },
  { id: "simple", label: "Clean", body: "Quiet chrome", icon: "clean", search: "clean simple minimal ui quiet chrome" },
  { id: "performance", label: "Fast", body: "Reduce lag", icon: "speed", search: "fast performance speed lag smooth" },
  { id: "focus", label: "Focus", body: "Hide extras", icon: "focus", search: "focus mode hide chrome workspace" },
  { id: "balanced", label: "Balanced", body: "Restore default", icon: "quick", search: "balanced restore default settings" }
];

function quickSetupPresetRailPanel() {
  const panel = document.createElement("div");
  panel.className = "quick-preset-rail";
  panel.dataset.settingsSearch = normalizeSettingsQuery("quick setup clean fast focus balanced preset simple performance restore default");
  for (const item of quickSetupPresetRailItems) {
    const preset = settingsPresetById(item.id);
    if (!preset) continue;
    const active = isActiveSettingsPreset(preset);
    const button = document.createElement("button");
    button.className = `quick-preset-rail-item${active ? " is-active" : ""}`;
    button.type = "button";
    button.disabled = active;
    button.setAttribute("aria-pressed", active ? "true" : "false");
    button.title = active ? `${item.label} preset is already active.` : `${item.label}: ${preset.body}`;
    button.dataset.settingsSearch = normalizeSettingsQuery(`quick setup preset ${item.label} ${item.body} ${preset.body} ${item.search}`);
    button.innerHTML = `
      <span class="quick-preset-rail-icon" aria-hidden="true"></span>
      <span class="quick-preset-rail-copy">
        <span class="quick-preset-rail-label"></span>
        <span class="quick-preset-rail-body"></span>
      </span>
    `;
    button.querySelector(".quick-preset-rail-icon").innerHTML = quickActionIconMarkup(item.icon);
    button.querySelector(".quick-preset-rail-label").textContent = item.label;
    button.querySelector(".quick-preset-rail-body").textContent = item.body;
    button.onclick = () => {
      if (!active) applySettingsPreset(preset);
    };
    panel.append(button);
  }
  return panel;
}

