const appearanceResetSettings = [
  "theme",
  "accent",
  "accentIntensity",
  "surfaceTint",
  "backgroundImage",
  "backgroundOpacity",
  "backgroundBlur",
  "backgroundFit",
  "backgroundRepeatMode",
  "backgroundPosition",
  "backgroundEffects",
  "backgroundChromeMode",
  "interfaceContrast",
  "interfaceDepth",
  "terminalBackground",
  "terminalForeground",
  "terminalCursorColor"
];

function settingsKeysMatchDefaults(keys) {
  return keys.every((key) => state.settings[key] === defaultSettings[key]);
}

function appearanceSettingsAreDefault() {
  return settingsKeysMatchDefaults(appearanceResetSettings);
}

function lookSettingsPayload() {
  const settings = {};
  for (const key of appearanceResetSettings) settings[key] = state.settings[key];
  return {
    version: 1,
    type: "cmux-look-settings",
    summary: {
      theme: optionLabel(themeOptions, state.settings.theme, state.settings.theme),
      accent: state.settings.accent,
      accentIntensity: optionLabel(accentIntensityOptions, state.settings.accentIntensity, state.settings.accentIntensity),
      surfaceTint: optionLabel(surfaceTintOptions, state.settings.surfaceTint, state.settings.surfaceTint),
      contrast: optionLabel(interfaceContrastOptions, state.settings.interfaceContrast, state.settings.interfaceContrast),
      depth: optionLabel(interfaceDepthOptions, state.settings.interfaceDepth, state.settings.interfaceDepth),
      background: appearanceBackgroundLabel(state.settings.backgroundImage),
      backgroundRepeat: optionLabel(backgroundRepeatOptions, state.settings.backgroundRepeatMode, state.settings.backgroundRepeatMode),
      backgroundChrome: optionLabel(backgroundChromeOptions, state.settings.backgroundChromeMode, state.settings.backgroundChromeMode),
      terminalColors: terminalColorPalettePayload().effective
    },
    settings
  };
}

async function copyLookSettings() {
  const payload = JSON.stringify(lookSettingsPayload(), null, 2);
  if (await writeClipboardText(payload)) {
    toast("Look settings copied.");
    return true;
  }
  await showTextDialog({
    title: "Look settings",
    message: "Clipboard access is unavailable. The current look setup is shown below.",
    value: payload,
    confirmLabel: "Close",
    multiline: true,
    readOnly: true
  });
  return false;
}

function optionIdAllowed(options, value) {
  return typeof value === "string" && options.some(([id]) => id === value);
}

function statusbarSummaryLabel(settings = state.settings) {
  if (settings.focusMode || !settings.showStatusbar) return "Hidden";
  return optionLabel(statusDetailOptions, settings.statusDetailMode, "Runtime");
}

function workspaceChromeSummaryForSettings(settings) {
  const normalized = {
    ...defaultSettings,
    ...state.settings,
    ...(settings || {})
  };
  return {
    density: normalized.density === "compact" ? "Compact" : "Comfortable",
    toolbar: optionLabel(toolbarModeOptions, normalized.toolbarMode, normalized.toolbarMode),
    topbarStyle: optionLabel(topbarStyleOptions, normalized.topbarStyle, normalized.topbarStyle),
    toolbarButtons: optionLabel(toolbarButtonStyleOptions, normalized.toolbarButtonStyle, normalized.toolbarButtonStyle),
    tabBar: normalized.showTabs ? optionLabel(tabBarStyleOptions, normalized.tabBarStyle, normalized.tabBarStyle) : "Hidden",
    sidebarStyle: normalized.focusMode ? "Hidden" : optionLabel(sidebarStyleOptions, normalized.sidebarStyle, normalized.sidebarStyle),
    sidebarTools: normalized.focusMode ? "Hidden" : optionLabel(sidebarToolOptions, normalized.sidebarToolMode, normalized.sidebarToolMode),
    emptyWorkspace: optionLabel(emptyWorkspaceModeOptions, normalized.emptyWorkspaceMode, normalized.emptyWorkspaceMode),
    inspectorStyle: optionLabel(inspectorStyleOptions, normalized.inspectorStyle, normalized.inspectorStyle),
    overlayStyle: optionLabel(overlayStyleOptions, normalized.overlayStyle, normalized.overlayStyle),
    switcherStyle: optionLabel(switcherStyleOptions, normalized.switcherStyle, normalized.switcherStyle),
    toastPlacement: optionLabel(toastPlacementOptions, normalized.toastPlacement, normalized.toastPlacement),
    paletteDensity: optionLabel(paletteDensityOptions, normalized.paletteDensity, normalized.paletteDensity),
    paletteQuickActions: optionLabel(paletteQuickActionsModeOptions, normalized.paletteQuickActionsMode, normalized.paletteQuickActionsMode),
    paletteDetail: optionLabel(paletteDetailModeOptions, normalized.paletteDetailMode, normalized.paletteDetailMode),
    paletteResults: optionLabel(paletteResultLimitOptions, normalized.paletteResultLimit, normalized.paletteResultLimit),
    palettePlacement: optionLabel(palettePlacementOptions, normalized.palettePlacement, normalized.palettePlacement),
    paneHeaders: optionLabel(paneHeaderOptions, normalized.paneHeaderMode, normalized.paneHeaderMode),
    paneControls: optionLabel(paneActionOptions, normalized.paneActionMode, normalized.paneActionMode),
    newPanePlacement: optionLabel(newPanePlacementOptions, normalized.newPanePlacement, normalized.newPanePlacement),
    paneSurface: optionLabel(paneSurfaceStyleOptions, normalized.paneSurfaceStyle, normalized.paneSurfaceStyle),
    workspaceRows: optionLabel(sidebarDetailOptions, normalized.sidebarDetailMode, normalized.sidebarDetailMode),
    workspaceRowSize: optionLabel(workspaceRowSizeOptions, normalized.workspaceRowSize, normalized.workspaceRowSize),
    activeWorkspace: optionLabel(workspaceActiveStyleOptions, normalized.workspaceActiveStyle, normalized.workspaceActiveStyle),
    workspaceColors: optionLabel(workspaceColorStyleOptions, normalized.workspaceColorStyle, normalized.workspaceColorStyle),
    toolbarLabels: optionLabel(toolbarLabelModeOptions, normalized.toolbarLabelMode, normalized.toolbarLabelMode),
    tabs: normalized.showTabs ? optionLabel(tabSizeOptions, normalized.tabSize, normalized.tabSize) : "Hidden",
    tabClose: normalized.showTabs ? optionLabel(tabCloseModeOptions, normalized.tabCloseMode, normalized.tabCloseMode) : "Hidden",
    activeTab: normalized.showTabs ? optionLabel(tabActiveStyleOptions, normalized.tabActiveStyle, normalized.tabActiveStyle) : "Hidden",
    corners: optionLabel(cornerStyleOptions, normalized.cornerStyle, normalized.cornerStyle),
    dividers: optionLabel(paneDividerSizeOptions, normalized.paneDividerSize, normalized.paneDividerSize),
    dividerStyle: optionLabel(paneDividerStyleOptions, normalized.paneDividerStyle, normalized.paneDividerStyle),
    paneSpacing: optionLabel(paneSpacingOptions, normalized.paneSpacing, normalized.paneSpacing),
    activePane: optionLabel(activePaneEmphasisOptions, normalized.activePaneEmphasis, normalized.activePaneEmphasis),
    inactivePane: optionLabel(inactivePaneDimmingOptions, normalized.inactivePaneDimming, normalized.inactivePaneDimming),
    markers: normalized.paneColorMarkers
      ? optionLabel(paneMarkerStyleOptions, normalized.paneMarkerStyle, normalized.paneMarkerStyle)
      : "Off",
    statusbar: statusbarSummaryLabel(normalized),
    statusbarStyle: normalized.focusMode || !normalized.showStatusbar
      ? "Hidden"
      : optionLabel(statusbarStyleOptions, normalized.statusbarStyle, normalized.statusbarStyle),
    focusMode: normalized.focusMode ? "On" : "Off",
    widths: `${normalized.sidebarWidth}px sidebar / ${normalized.inspectorWidth}px settings`
  };
}

function workspaceChromePayload(settingsSource = state.settings) {
  const source = {
    ...state.settings,
    ...(settingsSource || {})
  };
  const settings = {};
  for (const key of workspaceChromeSettings) settings[key] = source[key];
  return {
    version: 1,
    type: "cmux-workspace-chrome",
    summary: workspaceChromeSummaryForSettings(settings),
    settings
  };
}

async function copyWorkspaceChromePayload(
  payloadModel = workspaceChromePayload(),
  toastText = "Workspace chrome copied.",
  dialogMessage = "Clipboard access is unavailable. The workspace chrome setup is shown below."
) {
  const payload = JSON.stringify(payloadModel, null, 2);
  if (await writeClipboardText(payload)) {
    toast(toastText);
    return true;
  }
  await showTextDialog({
    title: "Workspace chrome settings",
    message: dialogMessage,
    value: payload,
    confirmLabel: "Close",
    multiline: true,
    readOnly: true
  });
  return false;
}

async function copyWorkspaceChromeSettings() {
  return copyWorkspaceChromePayload(workspaceChromePayload(), "Workspace chrome copied.");
}

function workspaceChromeSettingUpdateFromValue(key, raw) {
  if (key === "density") return ["comfortable", "compact"].includes(raw) ? raw : null;
  if (key === "paneHeaderMode") return optionIdAllowed(paneHeaderOptions, raw) ? raw : null;
  if (key === "paneActionMode") return optionIdAllowed(paneActionOptions, raw) ? raw : null;
  if (key === "newPanePlacement") return optionIdAllowed(newPanePlacementOptions, raw) ? raw : null;
  if (key === "paneSurfaceStyle") return optionIdAllowed(paneSurfaceStyleOptions, raw) ? raw : null;
  if (key === "sidebarDetailMode") return optionIdAllowed(sidebarDetailOptions, raw) ? raw : null;
  if (key === "sidebarBranchMode") return optionIdAllowed(sidebarBranchOptions, raw) ? raw : null;
  if (key === "sidebarFooterMode") return optionIdAllowed(sidebarFooterOptions, raw) ? raw : null;
  if (key === "sidebarStyle") return optionIdAllowed(sidebarStyleOptions, raw) ? raw : null;
  if (key === "sidebarToolMode") return optionIdAllowed(sidebarToolOptions, raw) ? raw : null;
  if (key === "emptyWorkspaceMode") return optionIdAllowed(emptyWorkspaceModeOptions, raw) ? raw : null;
  if (key === "inspectorStyle") return optionIdAllowed(inspectorStyleOptions, raw) ? raw : null;
  if (key === "overlayStyle") return optionIdAllowed(overlayStyleOptions, raw) ? raw : null;
  if (key === "switcherStyle") return optionIdAllowed(switcherStyleOptions, raw) ? raw : null;
  if (key === "toastPlacement") return optionIdAllowed(toastPlacementOptions, raw) ? raw : null;
  if (key === "paletteDensity") return optionIdAllowed(paletteDensityOptions, raw) ? raw : null;
  if (key === "paletteQuickActionsMode") return optionIdAllowed(paletteQuickActionsModeOptions, raw) ? raw : null;
  if (key === "paletteDetailMode") return optionIdAllowed(paletteDetailModeOptions, raw) ? raw : null;
  if (key === "paletteResultLimit") return optionIdAllowed(paletteResultLimitOptions, raw) ? raw : null;
  if (key === "palettePlacement") return optionIdAllowed(palettePlacementOptions, raw) ? raw : null;
  if (key === "workspaceRowSize") return optionIdAllowed(workspaceRowSizeOptions, raw) ? raw : null;
  if (key === "workspaceActiveStyle") return optionIdAllowed(workspaceActiveStyleOptions, raw) ? raw : null;
  if (key === "workspaceColorStyle") return optionIdAllowed(workspaceColorStyleOptions, raw) ? raw : null;
  if (key === "toolbarMode") return optionIdAllowed(toolbarModeOptions, raw) ? raw : null;
  if (key === "toolbarLabelMode") return optionIdAllowed(toolbarLabelModeOptions, raw) ? raw : null;
  if (key === "topbarStyle") return optionIdAllowed(topbarStyleOptions, raw) ? raw : null;
  if (key === "toolbarButtonStyle") return optionIdAllowed(toolbarButtonStyleOptions, raw) ? raw : null;
  if (key === "tabBarStyle") return optionIdAllowed(tabBarStyleOptions, raw) ? raw : null;
  if (key === "tabSize") return optionIdAllowed(tabSizeOptions, raw) ? raw : null;
  if (key === "tabCloseMode") return optionIdAllowed(tabCloseModeOptions, raw) ? raw : null;
  if (key === "tabActiveStyle") return optionIdAllowed(tabActiveStyleOptions, raw) ? raw : null;
  if (key === "addTabStyle") return optionIdAllowed(addTabStyleOptions, raw) ? raw : null;
  if (key === "cornerStyle") return optionIdAllowed(cornerStyleOptions, raw) ? raw : null;
  if (key === "paneDividerSize") return optionIdAllowed(paneDividerSizeOptions, raw) ? raw : null;
  if (key === "paneDividerStyle") return optionIdAllowed(paneDividerStyleOptions, raw) ? raw : null;
  if (key === "paneSpacing") return optionIdAllowed(paneSpacingOptions, raw) ? raw : null;
  if (key === "activePaneEmphasis") return optionIdAllowed(activePaneEmphasisOptions, raw) ? raw : null;
  if (key === "inactivePaneDimming") return optionIdAllowed(inactivePaneDimmingOptions, raw) ? raw : null;
  if (key === "titleDetailMode") return optionIdAllowed(titleDetailOptions, raw) ? raw : null;
  if (key === "paneMarkerStyle") return optionIdAllowed(paneMarkerStyleOptions, raw) ? raw : null;
  if (key === "statusDetailMode") return optionIdAllowed(statusDetailOptions, raw) ? raw : null;
  if (key === "statusbarStyle") return optionIdAllowed(statusbarStyleOptions, raw) ? raw : null;
  if (workspaceChromeBooleanSettings.has(key)) return typeof raw === "boolean" ? raw : null;
  const range = workspaceChromeWidthSettings[key];
  if (range) {
    if (raw === null || raw === "" || typeof raw === "boolean" || typeof raw === "object") return null;
    const value = Number(raw);
    return Number.isFinite(value) ? clamp(value, range[0], range[1]) : null;
  }
  return null;
}

function workspaceChromeUpdatesFromPayload(payload) {
  const parsed = importedObject(payload);
  const source = importedObject(parsed?.settings) || parsed;
  if (!source) return null;
  const updates = {};
  for (const key of workspaceChromeSettings) {
    if (!Object.prototype.hasOwnProperty.call(source, key)) continue;
    const value = workspaceChromeSettingUpdateFromValue(key, source[key]);
    if (value === null) return null;
    updates[key] = value;
  }
  return Object.keys(updates).length ? updates : null;
}

function applyWorkspaceChromeUpdates(updates, options = {}) {
  if (!updates) {
    toast("Clipboard does not contain workspace chrome settings.");
    return false;
  }
  const changed = updateSettings(updates, { immediate: true });
  if (!changed) {
    toast(options.alreadyText || "Workspace chrome already matches.");
    return false;
  }
  refreshLayoutSettings();
  toast(options.toastText || "Workspace chrome applied.");
  return true;
}

async function pasteWorkspaceChromeSettings() {
  const clipboard = await readClipboardText();
  if (!clipboard) {
    toast("Clipboard is empty.");
    return false;
  }
  try {
    const parsed = JSON.parse(clipboard);
    return applyWorkspaceChromeUpdates(workspaceChromeUpdatesFromPayload(parsed));
  } catch {
    toast("Clipboard does not contain workspace chrome settings.");
    return false;
  }
}

function workspaceChromePresetById(presetId) {
  return workspaceChromePresets.find((candidate) => candidate.id === presetId) || null;
}

function workspaceChromePresetSettings(preset) {
  return workspaceChromeUpdatesFromPayload({ settings: preset?.settings });
}

function workspaceChromePresetSearchText(preset, settings = workspaceChromePresetSettings(preset)) {
  const summary = workspaceChromeSummaryForSettings(settings || {});
  return normalizeSettingsQuery([
    "workspace chrome layout display preset apply copy simple clean compact focus toolbar label mode icons labels top bar style quiet subtle solid button style ghost subtle filled tab bar quiet banded sidebar rail tools primary hidden home screen empty workspace starter launchers guided compact quiet style quiet solid settings panel style inspector quiet subtle solid overlay style command palette menus dialogs toast feedback placement bottom right left top palette density compact balanced roomy search results quick actions auto hidden command list details metadata shortcuts compact labels result limit focused balanced extended placement position top center wide switcher style workspace pane keyboard hud row size density compact roomy workspace active row selected color marker dot edge tint tabs active selected underline status style quiet subtle solid pane header controls new pane placement split direction right below down surface corner radius rounded crisp soft divider grip line minimal slim balanced wide spacing gap gutter active pane highlight edge quiet line strong",
    preset?.label,
    preset?.body,
    summary.density,
    summary.toolbar,
    summary.toolbarLabels,
    summary.topbarStyle,
    summary.toolbarButtons,
    summary.tabBar,
    summary.sidebarStyle,
    summary.sidebarTools,
    summary.emptyWorkspace,
    summary.inspectorStyle,
    summary.overlayStyle,
    summary.switcherStyle,
    summary.toastPlacement,
    summary.paletteDensity,
    summary.paletteQuickActions,
    summary.paletteDetail,
    summary.paletteResults,
    summary.palettePlacement,
    summary.paneHeaders,
    summary.paneControls,
    summary.newPanePlacement,
    summary.paneSurface,
    summary.workspaceRows,
    summary.workspaceRowSize,
    summary.activeWorkspace,
    summary.workspaceColors,
    summary.tabs,
    summary.tabClose,
    summary.activeTab,
    summary.corners,
    summary.dividers,
    summary.dividerStyle,
    summary.paneSpacing,
    summary.activePane,
    summary.inactivePane,
    summary.markers,
    summary.statusbar,
    summary.statusbarStyle,
    summary.focusMode,
    summary.widths
  ].join(" "));
}

function isActiveWorkspaceChromePreset(preset) {
  const settings = workspaceChromePresetSettings(preset);
  if (!settings) return false;
  return Object.entries(settings).every(([key, value]) => state.settings[key] === value);
}

function workspaceChromePresetTitle(preset, active) {
  if (!preset) return "Choose a chrome preset first.";
  if (active) return `${preset.label} chrome is already active.`;
  return `Apply ${preset.label} workspace chrome.`;
}

function updateWorkspaceChromePresetButton(button, preset) {
  const settings = workspaceChromePresetSettings(preset);
  if (!settings) return;
  const active = isActiveWorkspaceChromePreset(preset);
  const card = button.closest(".workspace-chrome-preset-card");
  if (card) card.classList.toggle("is-active", active);
  setDisabledIfChanged(button, active);
  setTitleIfChanged(button, workspaceChromePresetTitle(preset, active));
  setAttributeIfChanged(button, "aria-pressed", active ? "true" : "false");
  const status = button.querySelector(".workspace-chrome-preset-status");
  if (status) setTextIfChanged(status, active ? "Active" : "");
  const search = workspaceChromePresetSearchText(preset, settings);
  if (button.dataset.settingsSearch !== search) {
    button.dataset.settingsSearch = search;
    updateSettingsSearchIndexItemSearch(button, search);
  }
  if (card && card.dataset.settingsSearch !== search) {
    card.dataset.settingsSearch = search;
    updateSettingsSearchIndexItemSearch(card, search);
  }
}

function applyWorkspaceChromePreset(presetId) {
  const preset = workspaceChromePresetById(presetId);
  const settings = workspaceChromePresetSettings(preset);
  if (!preset || !settings) {
    toast("Workspace chrome preset not found.");
    return false;
  }
  return applyWorkspaceChromeUpdates(settings, {
    toastText: `${preset.label} chrome applied.`,
    alreadyText: `${preset.label} chrome already active.`
  });
}

function copyWorkspaceChromePreset(presetId) {
  const preset = workspaceChromePresetById(presetId);
  const settings = workspaceChromePresetSettings(preset);
  if (!preset || !settings) {
    toast("Workspace chrome preset not found.");
    return false;
  }
  return copyWorkspaceChromePayload(
    workspaceChromePayload(settings),
    `${preset.label} chrome copied.`,
    "Clipboard access is unavailable. The chrome preset is shown below."
  );
}

function lookSettingUpdateFromValue(key, raw) {
  if (key === "theme") return optionIdAllowed(themeOptions, raw) ? raw : null;
  if (key === "accent") return normalizeUiColor(raw, "") || null;
  if (key === "accentIntensity") return optionIdAllowed(accentIntensityOptions, raw) ? raw : null;
  if (key === "surfaceTint") return optionIdAllowed(surfaceTintOptions, raw) ? raw : null;
  if (key === "backgroundImage") {
    if (raw === null) return "";
    if (typeof raw !== "string") return null;
    const trimmed = stripWrappingQuotes(raw);
    const normalized = normalizeBackgroundValue(raw);
    return trimmed && !normalized ? null : normalized;
  }
  if (key === "backgroundOpacity") {
    if (raw === null || raw === "" || typeof raw === "boolean" || typeof raw === "object") return null;
    const value = Number(raw);
    return Number.isFinite(value) ? clamp(value, 0, 42) : null;
  }
  if (key === "backgroundBlur") {
    if (raw === null || raw === "" || typeof raw === "boolean" || typeof raw === "object") return null;
    const value = Number(raw);
    return Number.isFinite(value) ? clamp(Math.round(value), 0, 12) : null;
  }
  if (key === "backgroundFit") return optionIdAllowed(backgroundFitOptions, raw) ? raw : null;
  if (key === "backgroundRepeatMode") return optionIdAllowed(backgroundRepeatOptions, raw) ? raw : null;
  if (key === "backgroundPosition") return optionIdAllowed(backgroundPositionOptions, raw) ? raw : null;
  if (key === "backgroundEffects") return optionIdAllowed(backgroundEffectsOptions, raw) ? raw : null;
  if (key === "backgroundChromeMode") return optionIdAllowed(backgroundChromeOptions, raw) ? raw : null;
  if (key === "interfaceContrast") return optionIdAllowed(interfaceContrastOptions, raw) ? raw : null;
  if (key === "interfaceDepth") return optionIdAllowed(interfaceDepthOptions, raw) ? raw : null;
  if (key === "terminalBackground" || key === "terminalForeground" || key === "terminalCursorColor") {
    if (raw === "" || raw === null) return "";
    return typeof raw === "string" ? normalizeTerminalColor(raw) || null : null;
  }
  return null;
}

function lookSettingsUpdatesFromPayload(payload) {
  const parsed = importedObject(payload);
  const source = importedObject(parsed?.settings) || parsed;
  if (!source) return null;
  const updates = {};
  for (const key of appearanceResetSettings) {
    if (!Object.prototype.hasOwnProperty.call(source, key)) continue;
    const value = lookSettingUpdateFromValue(key, source[key]);
    if (value === null) return null;
    updates[key] = value;
  }
  return Object.keys(updates).length ? updates : null;
}

function applyLookSettingsUpdates(updates, toastText = "Look settings applied.") {
  if (!updates) {
    toast("Clipboard does not contain look settings.");
    return false;
  }
  const changed = updateSettings(updates);
  if (!changed) {
    toast("Look settings already match.");
    return false;
  }
  renderSettingsInspector();
  toast(toastText);
  return true;
}

async function pasteLookSettings() {
  const clipboard = await readClipboardText();
  if (!clipboard) {
    toast("Clipboard is empty.");
    return false;
  }
  try {
    const parsed = JSON.parse(clipboard);
    return applyLookSettingsUpdates(lookSettingsUpdatesFromPayload(parsed));
  } catch {
    toast("Clipboard does not contain look settings.");
    return false;
  }
}

function workspaceChromeSettingsAreDefault() {
  return settingsKeysMatchDefaults(workspaceChromeSettings);
}

function toggleFocusMode(nextValue = !state.settings.focusMode, options = {}) {
  const enabled = Boolean(nextValue);
  const changed = updateSettings({ focusMode: enabled }, { immediate: true });
  if (!changed) {
    if (options.toast !== false) toast(`Focus mode already ${enabled ? "on" : "off"}.`);
    return false;
  }
  refreshLayoutSettings({ ifChanged: true });
  if (options.toast !== false) toast(`Focus mode ${enabled ? "on" : "off"}.`);
  return true;
}

function resetAppearanceSettings() {
  const updates = {};
  for (const key of appearanceResetSettings) updates[key] = defaultSettings[key];
  const changed = updateSettings(updates, { immediate: true });
  if (!changed) {
    toast("Look settings already reset.");
    return false;
  }
  renderSettingsInspector();
  toast("Look settings reset.");
  return true;
}

function resetWorkspaceChrome() {
  const updates = {};
  for (const key of workspaceChromeSettings) updates[key] = defaultSettings[key];
  const changed = updateSettings(updates, { immediate: true });
  if (!changed) {
    toast("Workspace chrome already reset.");
    return;
  }
  refreshLayoutSettings();
  toast("Workspace chrome reset.");
}

function resetActivePaneLayout() {
  const workspace = activeWorkspace();
  if (!workspace || workspace.panels.length <= 1) {
    toast("Open another pane to reset split layout.");
    return;
  }
  state.paneTrees.set(workspace.id, equalizePaneTree(paneTreeForWorkspace(workspace)));
  savePaneTreeLayouts(state.paneTrees);
  for (const panel of workspace.panels) state.paneLayouts.delete(panel.id);
  savePaneLayouts();
  render();
  refreshLayoutSettings();
  requestAnimationFrame(() => {
    for (const panel of workspace.panels) {
      const terminal = state.terminals.get(panel.id);
      if (terminal) scheduleFitTerminal(terminal, true);
    }
  });
  toast("Split layout reset.");
}

function combinePaneTrees(nodes, direction) {
  let tree = null;
  let count = 0;
  for (const node of nodes) {
    if (!node) continue;
    if (!tree) {
      tree = node;
      count = 1;
      continue;
    }
    tree = paneTreeSplit(direction, tree, node, count / (count + 1));
    count += 1;
  }
  return tree;
}

function buildGridPanePresetTree(panelIds) {
  const ids = panelIds.filter(Boolean);
  if (ids.length <= 2) return buildPaneTreeFromPanelIds(ids, "right");
  const columnCount = Math.ceil(Math.sqrt(ids.length));
  const rows = [];
  for (let index = 0; index < ids.length; index += columnCount) {
    rows.push(ids.slice(index, index + columnCount));
  }
  const rowTrees = rows.map((rowIds) => buildPaneTreeFromPanelIds(rowIds, "right"));
  return combinePaneTrees(rowTrees, "down");
}

async function applyPaneLayoutPreset(presetId, options = {}) {
  const preset = paneLayoutPresets.find((candidate) => candidate.id === presetId);
  const workspace = options.workspaceId
    ? state.data?.workspaces.find((candidate) => candidate.id === options.workspaceId)
    : activeWorkspace();
  const active = options.panelId
    ? workspace?.panels.find((panel) => panel.id === options.panelId)
    : activePanel();
  if (!preset || !workspace || workspace.panels.length <= 1 || !active) {
    toast("Open another pane to use layout presets.");
    return false;
  }
  if (state.data.activeWorkspaceId !== workspace.id || workspace.activePanelId !== active.id) {
    workspace.activePanelId = active.id;
    state.data.activeWorkspaceId = workspace.id;
    state.focusedPanelId = active.id;
    state.lastInteractedPanelId = active.id;
    refreshAppStateSignature();
    queueFocusSync({ type: "panel", panelId: active.id });
  }
  const direction = preset.direction || paneLayoutDirection(workspace);
  clearZoomedPanelForWorkspace(workspace);
  if (paneLayoutDirection(workspace) !== direction) {
    await updatePanel(active.id, { direction });
  }
  const nextWorkspace = activeWorkspace() || workspace;
  let tree = paneTreeForWorkspace(nextWorkspace);
  if (preset.id === "equal") {
    tree = equalizePaneTree(tree);
  } else if (preset.mode === "grid") {
    tree = buildGridPanePresetTree(nextWorkspace.panels.map((panel) => panel.id));
  } else if (preset.mode === "active") {
    tree = buildActivePanePresetTree(nextWorkspace.panels, active.id, direction, nextWorkspace.panels.length === 2 ? 68 : 60);
  } else {
    tree = buildPaneTreeFromPanelIds(nextWorkspace.panels.map((panel) => panel.id), direction);
  }
  state.paneTrees.set(nextWorkspace.id, tree);
  savePaneTreeLayouts(state.paneTrees);
  render();
  refreshLayoutSettings();
  requestAnimationFrame(() => {
    for (const panel of nextWorkspace.panels) {
      const terminal = state.terminals.get(panel.id);
      if (terminal) scheduleFitTerminal(terminal, true);
    }
  });
  toast(`${preset.label} layout applied.`);
  return true;
}

async function promptActivePaneLayoutPercent() {
  const workspace = activeWorkspace();
  if (!workspace || workspace.panels.length <= 1) {
    toast("Open another pane to resize the active pane.");
    return false;
  }
  const value = await showTextDialog({
    title: "Set active pane size",
    message: `Enter a percentage from ${paneLayoutPercentMin} to ${paneLayoutPercentMax}.`,
    value: String(activePaneLayoutPercent(workspace)),
    placeholder: "65",
    confirmLabel: "Apply"
  });
  if (value === null) return false;
  const parsed = Number(value);
  if (!Number.isFinite(parsed)) {
    toast(`Enter a number from ${paneLayoutPercentMin} to ${paneLayoutPercentMax}.`);
    return false;
  }
  applyActivePaneLayoutPercent(parsed, { save: true, toast: true });
  refreshLayoutSettings();
  return true;
}

function queueTerminalFontSizeSync(panelId, fontSize) {
  const found = findPanelState(panelId);
  if (!found || found.panel.type !== "terminal") return false;
  const size = Number(fontSize);
  state.pendingTerminalFontSizeSync.set(panelId, Number.isFinite(size) && size <= 0 ? 0 : normalizeTerminalFontSize(fontSize, state.settings.terminalFontSize));
  const previousTimer = state.terminalFontSizeSyncTimers.get(panelId);
  if (previousTimer) clearTimeout(previousTimer);
  state.terminalFontSizeSyncTimers.set(panelId, setTimeout(() => {
    flushTerminalFontSizeSync({ panelIds: [panelId] });
  }, 220));
  return true;
}

async function terminalFontSizeSyncFetch(panelId, terminalFontSize, options = {}) {
  const response = await fetch(`/api/panels/${panelId}`, {
    method: "PATCH",
    headers: {
      "content-type": "application/json",
      ...(launchToken ? { "x-local-token": launchToken } : {})
    },
    body: JSON.stringify({ terminalFontSize }),
    keepalive: Boolean(options.keepalive)
  });
  if (!response.ok) throw new Error(await response.text());
  return response;
}

async function flushTerminalFontSizeSync(options = {}) {
  const requestedPanelIds = Array.isArray(options.panelIds)
    ? new Set(options.panelIds.filter(Boolean))
    : null;
  const panelIdsToClear = requestedPanelIds || new Set(state.terminalFontSizeSyncTimers.keys());
  for (const panelId of panelIdsToClear) {
    const timer = state.terminalFontSizeSyncTimers.get(panelId);
    if (timer) clearTimeout(timer);
    state.terminalFontSizeSyncTimers.delete(panelId);
  }
  const entries = [...state.pendingTerminalFontSizeSync.entries()]
    .filter(([panelId]) => !requestedPanelIds || requestedPanelIds.has(panelId));
  for (const [panelId] of entries) state.pendingTerminalFontSizeSync.delete(panelId);
  await Promise.all(entries.map(async ([panelId, terminalFontSize]) => {
    const found = findPanelState(panelId);
    if (!found || found.panel.type !== "terminal" || normalizeTerminalFontSize(found.panel.terminalFontSize, 0) !== terminalFontSize) return;
    try {
      await terminalFontSizeSyncFetch(panelId, terminalFontSize, options);
    } catch {
      // The pane may have been closed before the debounce fired.
    }
  }));
}

function refreshActivePaneTextControls(panelId) {
  const found = findPanelState(panelId);
  if (!found || found.panel.type !== "terminal" || !elements.inspectorBody) return;
  const nextSize = terminalFontSizeForPanel(found.panel);
  const hasOverride = panelHasTerminalFontSize(found.panel);
  for (const row of elements.inspectorBody.querySelectorAll("[data-active-pane-text-row]")) {
    if (row.dataset.activePaneTextRow !== panelId) continue;
    setTextIfChanged(row.querySelector(".setting-label"), `Pane text ${nextSize}px`);
  }
  for (const range of elements.inspectorBody.querySelectorAll("[data-active-pane-text-range]")) {
    if (range.dataset.activePaneTextRange === panelId) range.value = String(nextSize);
  }
  for (const number of elements.inspectorBody.querySelectorAll("[data-active-pane-text-number]")) {
    if (number.dataset.activePaneTextNumber === panelId) number.value = String(nextSize);
  }
  for (const button of elements.inspectorBody.querySelectorAll("[data-active-pane-reset-text]")) {
    if (button.dataset.activePaneResetText === panelId) button.disabled = !hasOverride;
  }
}

function setPaneTerminalFontSizeOverride(panelId, fontSize, options = {}) {
  const found = findPanelState(panelId);
  if (!found || found.panel.type !== "terminal") return 0;
  const override = Number(fontSize) <= 0
    ? 0
    : normalizeTerminalFontSize(fontSize, terminalFontSizeForPanel(found.panel));
  const currentOverride = normalizeTerminalFontSize(found.panel.terminalFontSize, 0);
  if (currentOverride === override) {
    refreshActivePaneTextControls(panelId);
    return terminalFontSizeForPanel(found.panel);
  }
  found.panel.terminalFontSize = override;
  const nextSize = terminalFontSizeForPanel(found.panel);
  const session = state.terminals.get(panelId);
  if (session) {
    session.fontSize = nextSize;
    session.term.options.fontSize = nextSize;
    scheduleFitTerminal(session, true);
  }
  queueTerminalFontSizeSync(panelId, override);
  refreshActivePaneTextControls(panelId);
  if (options.toast !== false) {
    toast(override ? `Pane text ${nextSize}px.` : `Pane text reset to ${nextSize}px.`);
  }
  return nextSize;
}

function showTerminalTextSizeStatus(panelId, size) {
  const session = state.terminals.get(panelId);
  if (!session || session.disposed) return;
  if (!session.hasOutput && session.host.classList.contains("is-connecting")) return;
  setTerminalConnectionStatus(session, "ready", `Text ${size}px`, 650);
}

function changeTerminalFontSize(delta, options = {}) {
  const panel = resolveTerminalPanel(options.panel || (options.event ? keyboardPanelFromEvent(options.event) : null) || activePaneActionTarget());
  if (!panel) return false;
  if (options.focus === false) {
    const active = activeWorkspace();
    if (active?.activePanelId === panel.id) markInteractedPanel(panel.id);
  } else {
    markInteractedPanel(panel.id);
  }
  const currentSize = terminalFontSizeForPanel(panel);
  const nextSize = normalizeTerminalFontSize(currentSize + delta, currentSize);
  if (nextSize === currentSize) return false;
  panel.terminalFontSize = nextSize;
  const session = state.terminals.get(panel.id);
  if (session) {
    session.fontSize = nextSize;
    session.term.options.fontSize = nextSize;
    scheduleFitTerminal(session, true);
  }
  queueTerminalFontSizeSync(panel.id, nextSize);
  refreshActivePaneTextControls(panel.id);
  if (options.status) showTerminalTextSizeStatus(panel.id, nextSize);
  if (options.toast !== false) toast(`Pane text ${nextSize}px`);
  return true;
}

function changePaneTerminalFontSize(panelId, delta, options = {}) {
  const found = findPanelState(panelId);
  if (!found || found.panel.type !== "terminal") return false;
  focusPanel(panelId);
  return changeTerminalFontSize(delta, { panel: found.panel, ...options });
}

function resetTerminalFontSize(options = {}) {
  const panel = resolveTerminalPanel(options.panel || (options.event ? keyboardPanelFromEvent(options.event) : null) || activePaneActionTarget());
  if (!panel) return false;
  markInteractedPanel(panel.id);
  if (!panelHasTerminalFontSize(panel)) {
    if (options.toast !== false) toast(`Pane text already uses ${state.settings.terminalFontSize}px default.`);
    return false;
  }
  panel.terminalFontSize = 0;
  const nextSize = terminalFontSizeForPanel(panel);
  const session = state.terminals.get(panel.id);
  if (session) {
    session.fontSize = nextSize;
    session.term.options.fontSize = nextSize;
    scheduleFitTerminal(session, true);
  }
  queueTerminalFontSizeSync(panel.id, 0);
  refreshActivePaneTextControls(panel.id);
  if (options.status) showTerminalTextSizeStatus(panel.id, nextSize);
  if (options.toast !== false) toast(`Pane text reset to ${nextSize}px.`);
  return true;
}

function resetPaneTerminalFontSize(panelId, options = {}) {
  const found = findPanelState(panelId);
  if (!found || found.panel.type !== "terminal") return false;
  focusPanel(panelId);
  return resetTerminalFontSize({ panel: found.panel, ...options });
}

async function writeClipboardText(text) {
  try {
    if (navigator.clipboard?.writeText) {
      await navigator.clipboard.writeText(text);
      return true;
    }
  } catch {
    // Fall back to the native bridge below.
  }
  if (window.cmuxNative?.writeClipboard) {
    await window.cmuxNative.writeClipboard(text);
    return true;
  }
  return false;
}

async function readClipboardText() {
  try {
    if (navigator.clipboard?.readText) return await navigator.clipboard.readText();
  } catch {
    // Fall back to the native bridge below.
  }
  if (window.cmuxNative?.readClipboard) return await window.cmuxNative.readClipboard();
  return "";
}

async function sendTerminalInput(panelId, text) {
  const payload = String(text ?? "");
  if (!payload) return false;
  const session = state.terminals.get(panelId);
  if (session?.socket?.readyState === WebSocket.OPEN) {
    session.socket.send(JSON.stringify({ type: "input", data: payload }));
    return true;
  }
  try {
    const result = await api("/api/input", {
      method: "POST",
      body: JSON.stringify({ panelId, text: payload })
    });
    return Boolean(result.ok);
  } catch {
    return false;
  }
}

async function runTerminalCommand(command, panel = activePanel(), options = {}) {
  const terminalPanel = resolveTerminalPanel(panel);
  if (!terminalPanel) {
    toast("Focus a terminal pane first.");
    return false;
  }
  const normalized = normalizeTerminalCommand(command);
  if (!normalized) return false;
  const ok = await sendTerminalInput(terminalPanel.id, `${normalized}\r`);
  if (!ok) {
    toast("Terminal is not ready.");
    return false;
  }
  rememberRecentCommand(normalized);
  if (options.renderSettings) renderSettingsInspector();
  focusPanel(terminalPanel.id);
  focusTerminalSession(terminalPanel.id);
  return true;
}

async function promptRunTerminalCommand(panel = activePanel()) {
  const terminalPanel = resolveTerminalPanel(panel);
  if (!terminalPanel) {
    toast("Focus a terminal pane first.");
    return false;
  }
  const command = await showTextDialog({
    title: "Run command",
    message: "Send a command to the active terminal.",
    value: state.recentCommands[0] || "",
    placeholder: "npm run dev",
    confirmLabel: "Run"
  });
  if (command === null) return false;
  return runTerminalCommand(command, terminalPanel, { renderSettings: state.inspectorMode === "settings" });
}

function runTerminalCommandSnippet(snippetId) {
  const snippet = findTerminalCommandSnippet(snippetId);
  if (!snippet) return false;
  return runTerminalCommand(snippet.command);
}

async function copyActiveTerminalSelection(panel = activePanel()) {
  const terminalPanel = resolveTerminalPanel(panel);
  if (!terminalPanel) {
    toast("Focus a terminal pane first.");
    return false;
  }
  const selection = state.terminals.get(terminalPanel.id)?.term?.getSelection?.() || "";
  if (!selection) {
    toast("Select terminal text first.");
    focusTerminalSession(terminalPanel.id);
    return false;
  }
  if (await writeClipboardText(selection)) {
    toast("Terminal selection copied.");
    return true;
  }
  toast("Clipboard is unavailable.");
  return false;
}

async function pasteClipboardToTerminal(panel = activePanel()) {
  const terminalPanel = resolveTerminalPanel(panel);
  if (!terminalPanel) {
    toast("Focus a terminal pane first.");
    return false;
  }
  const clipboard = await readClipboardText();
  if (!clipboard) {
    toast("Clipboard is empty.");
    focusTerminalSession(terminalPanel.id);
    return false;
  }
  const ok = await sendTerminalInput(terminalPanel.id, clipboard);
  if (!ok) {
    toast("Terminal is not ready.");
    return false;
  }
  focusPanel(terminalPanel.id);
  focusTerminalSession(terminalPanel.id);
  return true;
}

